diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..efd479ec7 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2030,7 +2030,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 			fz_dump_blend(ctx, "/GA=", state[1].group_alpha);
 #endif

-		fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);
+		if (pixmap)
+			fz_paint_image(ctx, state[1].mask, &bbox, state[1].shape, state[1].group_alpha, pixmap, local_ctm, 255, !(devp->hints & FZ_DONT_INTERPOLATE_IMAGES), 0);

 #ifdef DUMP_GROUP_BLENDS
 		fz_dump_blend(ctx, " to get ", state[1].mask);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..f9740d0e5 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1837,7 +1837,14 @@ fz_draw_fill_image(fz_context *ctx, fz_device *devp, fz_image *image, fz_matrix
 	fz_always(ctx)
 		fz_drop_pixmap(ctx, pixmap);
 	fz_catch(ctx)
+	{
+		state[1].scissor = fz_empty_irect;
+		state[1].mask = NULL;
+		state[1].dest = NULL;
+		state[1].shape = NULL;
+		state[1].group_alpha = NULL;
 		fz_rethrow(ctx);
+	}
 }

 static void

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..e47446342 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1835,7 +1835,10 @@ fz_draw_fill_image(fz_context *ctx, fz_device *devp, fz_image *image, fz_matrix
 			fz_knockout_end(ctx, dev);
 	}
 	fz_always(ctx)
-		fz_drop_pixmap(ctx, pixmap);
+	{
+		if (pixmap)
+			fz_drop_pixmap(ctx, pixmap);
+	}
 	fz_catch(ctx)
 		fz_rethrow(ctx);
 }

